import { AnyAction } from 'redux';

import { IAuth } from '../../pages/auth-page/auth-page-types';

const INITIAL_STATE = {
  isAuth: false,
  isLoading: false,
};

export const authReducer = (
  state: IAuth | {} = INITIAL_STATE,
  { type, payload }: AnyAction,
) => {
  switch (type) {
    case 'SET_IS_AUTH':
      return {
        ...state,
        ...payload,
      };
    case 'SET_IS_LOADING':
      return {
        ...state,
        ...payload,
      };
    default:
      return state
  }
};
