import { ConnectedProps, connect } from 'react-redux';
import { createStructuredSelector } from 'reselect';

import { checkAuth } from './private-route-actions';
import { createSelector } from "@reduxjs/toolkit";

import { AUTH_STORE_KEY } from "@/pages/auth-page";
import { getIsAuth, getIsLoading } from './private-route-selectors';


const mapStateToProps = createStructuredSelector({
  isAuth: getIsAuth,
  isLoading: getIsLoading,
});

const mapDispatchToProps = (dispatch: Function) => ({
  checkAuth: () => dispatch(checkAuth()),
});

export const withPrivateRouteConnector = connect(mapStateToProps, mapDispatchToProps);

export type TPrivateRouteConnector = ConnectedProps<typeof withPrivateRouteConnector>;
