import { useCallback, useState } from "react";
import { QrScanDecodedError } from "./qr-scan-decoded-error";
import { IQrScanDecodedError } from "./qr-scan-decoded-error-types";

export const QrScanDecodedErrorController = ({
  isDecodedTextValid,
}: IQrScanDecodedError) => {
  const [isClosed, setIsClosed] = useState<boolean>(false);

  const onClickClose = useCallback(() => {
    setIsClosed(true);
  }, []);

  return (isDecodedTextValid === false && !isClosed)
    ? <QrScanDecodedError onClickClose={onClickClose} />
    : null;
}