import { createSelector } from "@reduxjs/toolkit";

import { AUTH_STORE_KEY } from "@/pages/auth-page";

const getAuth = (state: any) => state[AUTH_STORE_KEY];

export const getIsAuth = createSelector(
  getAuth,
  (auth) => auth.isAuth,
);

export const getIsLoading = createSelector(
  getAuth,
  (auth) => auth.isLoading,
);
