import { useCallback } from "react";
import { useNavigate } from "react-router-dom";

import { AuthForm } from "./auth-form";
import { withAuthFormConnector } from "./auth-form-connector";
import { IAuthForm } from "./auth-form-types";

export const AuthFormContainer = ({
  login,
}: any) => {
  const navigate = useNavigate();

  const onSubmit = useCallback(async (values: IAuthForm) => {
    const requestResult = await login(values.username, values.password);

    if (requestResult.status === "success") {
      navigate('/');
    }

    if (requestResult.status === "error") {
      return requestResult.result;
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return <AuthForm onSubmit={onSubmit} />
};

export const AuthFormController =
  withAuthFormConnector(
    AuthFormContainer
  );
