import { Form, Field } from 'react-final-form';
import classNames from "classnames";

import { Button } from "@/components/button";
import { TField } from '@/types';

import { FIELDS } from "./auth-form-config";
import { IProps } from "./auth-form-types";
import { FORM_ERROR_TEXT, FORM_ERROR_NOTE } from './auth-form-constants';

import styles from "./auth-form-styles.module.scss";

export const AuthForm = ({
  onSubmit
}: IProps) => {
  return (
    <>
      <Form
        onSubmit={onSubmit}
        render={({
          form,
          handleSubmit,
          values,
          submitError,
        }: any) => {
          return (
            <>
              <p
                className={classNames(styles["error-note"], { [styles["error-note_show"]]: submitError === FORM_ERROR_TEXT })}
              >
                {FORM_ERROR_NOTE}
              </p>
              <form
                className={styles.form}
                onSubmit={handleSubmit}
              >
                {
                  FIELDS.map((field: TField) => (
                    <Field
                      key={field.name}
                      name={field.name}
                      component={field.component}
                      required
                      placeholder={field.placeholder}
                      className={classNames(styles.input, { [styles["field-error"]]: submitError === FORM_ERROR_TEXT })}
                    // isSubmitError={Boolean(submitError)}
                    />
                  ))
                }
                <Button type="submit">Войти</Button>
              </form>
            </>
          )
        }}
      ></Form >
    </>
  )
};
