import React, { useEffect, useState } from 'react';
import { Navigate, Outlet } from 'react-router-dom';
import { PrivateRoute } from './private-route';
import { Header } from '../header';
import { Menu } from '../menu';
import { checkAuth } from './private-route-actions';

import styles from "./private-route-styles.module.scss";
import { Loader } from '../loader';
import { withPrivateRouteConnector } from './private-route-connector';
import { IPrivateRouteContainerProps } from './private-route-types';

const PrivateRouteContainer = ({
  isAuth,
  isLoading,
  checkAuth,
}: IPrivateRouteContainerProps) => {
  const [checkAuthLoading, setCheckAuthLoading] = useState<boolean>(true);

  const makeCheckAuth = async () => {
    await checkAuth();
    setCheckAuthLoading(false);
  }

  useEffect(() => {
    makeCheckAuth();
  }, []);

  return <PrivateRoute isAuth={isAuth} isLoading={checkAuthLoading} />
}

export const PrivateRouteController =
  withPrivateRouteConnector(
    PrivateRouteContainer
  );