import { useEffect, memo } from 'react';
import { Html5Qrcode } from "html5-qrcode";

import { QrScanDecodedError } from './components/qr-scan-decoded-error';

import { QR_SCAN_NOTE } from './qr-scan-constants';

import { IQrScanProps } from './qr-scan-types';

import styles from "./qr-scan-styles.module.scss";
import "./qr-scan-styles.scss";
import classNames from 'classnames';

const qrConfig = {
  fps: 10,
  qrbox: { width: 200, height: 200 },
};

export const QrScan = memo(({
  isDecodedTextValid,
  qrCodeSuccessCallback,
  qrCodeFailureCallback,
}: IQrScanProps) => {
  useEffect(() => {
    console.log('here');
    let html5QrCode: any = new Html5Qrcode("reader");

    html5QrCode.start(
      { facingMode: "environment" },
      qrConfig,
      qrCodeSuccessCallback,
      // qrCodeFailureCallback,
    ).then(async () => {
      if (isTorchSupported(html5QrCode)) {
        let constraints: any = {
          ...qrConfig,
          torch: true,
          advanced: [
            { torch: true }
          ]
        };

        await html5QrCode.applyVideoConstraints(constraints);

        let settings = html5QrCode.getRunningTrackSettings();

        if (settings.torch === true) {
          alert("torch here");
        } else {
          alert("torch fail");
        }
      }
    });

    return () => {
      // console.log('destroy scan');
      try {
        html5QrCode
          .stop()
          .then((res: any) => {
            console.log('here');
            html5QrCode.clear();
          })
          .catch((err: any) => {
            console.log(err.message);
          });
      } catch (err) {
        console.log(err);
      }
    }
  }, []);

  function isTorchSupported(html5Qrcode: Html5Qrcode): boolean {
    let settings = html5Qrcode.getRunningTrackSettings();
    alert("torch" in settings);
    return "torch" in settings;
  }


  return (
    <section className={styles.container}>
      <div
        id="reader"
        className={classNames({ "box-orange": isDecodedTextValid === false })}>
        2
      </div>
      <div className={styles["note-wrapper"]}>
        <p className={styles["note"]}>{QR_SCAN_NOTE}</p>
      </div>
      <QrScanDecodedError isDecodedTextValid={isDecodedTextValid} />
    </section>
  );
});
